// Cache the (pre-state) target endpoint pointer.
let target_endpoint: EndpointPtr =
    pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap();

// r1 and r2 are both unit `()`, so they are trivially equal.
assert(r1 == r2);

// ---- Domain equalities (post1 == pre, post2 == pre, hence post1 == post2). ----
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());

assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());

assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());

assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());

// ---- page_closure is preserved on both runs. ----
assert(post1_self_.page_closure() =~= pre_self_.page_closure());
assert(post2_self_.page_closure() =~= pre_self_.page_closure());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

// ---- Re-inject the four "pre vs post" forall ensures with explicit triggers
//      that match the synthetic det_<f>_equal forall (`postN_self_.get_X(p)`). ----
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
        ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
        ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));

assert(forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr)
        ==> post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr)
        ==> post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));

assert(forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
        ==> pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![trigger post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
        ==> pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));

assert(forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_endpoint
        ==> pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_endpoint
        ==> pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));

// ---- Mutated thread (thread_ptr): pin every ensured field on both runs. ----
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
    =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors);

assert(post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
assert(post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
assert(post1_self_.get_thread(thread_ptr).ipc_payload
    =~= post2_self_.get_thread(thread_ptr).ipc_payload);

assert(post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
assert(post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
assert(post1_self_.get_thread(thread_ptr).state
    == post2_self_.get_thread(thread_ptr).state);

// ---- Mutated endpoint (target_endpoint): pin every ensured field on both runs. ----
assert(post1_self_.get_endpoint(target_endpoint).queue_state
    == pre_self_.get_endpoint(target_endpoint).queue_state);
assert(post2_self_.get_endpoint(target_endpoint).queue_state
    == pre_self_.get_endpoint(target_endpoint).queue_state);
assert(post1_self_.get_endpoint(target_endpoint).queue_state
    == post2_self_.get_endpoint(target_endpoint).queue_state);

assert(post1_self_.get_endpoint(target_endpoint).owning_threads
    == pre_self_.get_endpoint(target_endpoint).owning_threads);
assert(post2_self_.get_endpoint(target_endpoint).owning_threads
    == pre_self_.get_endpoint(target_endpoint).owning_threads);
assert(post1_self_.get_endpoint(target_endpoint).owning_threads
    == post2_self_.get_endpoint(target_endpoint).owning_threads);

assert(post1_self_.get_endpoint(target_endpoint).queue@
    == pre_self_.get_endpoint(target_endpoint).queue@.push(thread_ptr));
assert(post2_self_.get_endpoint(target_endpoint).queue@
    == pre_self_.get_endpoint(target_endpoint).queue@.push(thread_ptr));
assert(post1_self_.get_endpoint(target_endpoint).queue@
    =~= post2_self_.get_endpoint(target_endpoint).queue@);

// ---- Final lift: pointwise spec-accessor equality between post1 and post2,
//      indexed by post1's domain (matches the typical det_<f>_equal forall shape). ----
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr)
by {
    assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
    assert(pre_self_.proc_dom().contains(p_ptr));
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
};

assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
    post1_self_.container_dom().contains(c_ptr)
    implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr)
by {
    assert(post1_self_.container_dom() == pre_self_.container_dom());
    assert(pre_self_.container_dom().contains(c_ptr));
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
};

assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr), post2_self_.get_thread(t_ptr)]
    post1_self_.thread_dom().contains(t_ptr)
    implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr)
by {
    assert(post1_self_.thread_dom() == pre_self_.thread_dom());
    assert(post2_self_.thread_dom() == pre_self_.thread_dom());
    assert(pre_self_.thread_dom().contains(t_ptr));
    if t_ptr == thread_ptr {
        // Each ensured field of the mutated thread is pinned identically on both runs.
        assert(post1_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post2_self_.get_thread(t_ptr).endpoint_descriptors);
        assert(post1_self_.get_thread(t_ptr).ipc_payload
            =~= post2_self_.get_thread(t_ptr).ipc_payload);
        assert(post1_self_.get_thread(t_ptr).state
            == post2_self_.get_thread(t_ptr).state);
    } else {
        assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
        assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
    }
};

assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr)
    implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr)
by {
    assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
    assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());
    assert(pre_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    if e_ptr == target_endpoint {
        // Each ensured field of the mutated endpoint is pinned identically on both runs.
        assert(post1_self_.get_endpoint(e_ptr).queue_state
            == post2_self_.get_endpoint(e_ptr).queue_state);
        assert(post1_self_.get_endpoint(e_ptr).owning_threads
            == post2_self_.get_endpoint(e_ptr).owning_threads);
        assert(post1_self_.get_endpoint(e_ptr).queue@
            =~= post2_self_.get_endpoint(e_ptr).queue@);
    } else {
        assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
    }
};

// ---- Last-ditch structural equality of the two post-states. ----
assert(post1_self_ =~= post2_self_);
